import json
import re
import os

# Load existing temp questions if exists
all_new_questions = []
if os.path.exists('temp_new_questions.json'):
    with open('temp_new_questions.json', 'r', encoding='utf-8') as f:
        all_new_questions = json.load(f)
    print(f"Loaded {len(all_new_questions)} from temp file")

# Count current categories to know what we need
with open('index.html', 'r', encoding='utf-8') as f:
    html = f.read()

pattern = r'const BUILTIN_QUESTIONS=\[([\s\S]*?)\];'
match = re.search(pattern, html)
questions_str = match.group(1) if match else ""
categories = {}
for m in re.finditer(r"category:'(\w[\w-]*)'", questions_str):
    cat = m.group(1)
    categories[cat] = categories.get(cat, 0) + 1

print("\nCurrent counts:")
total = sum(categories.values())
print(f"Total: {total}")
for cat in sorted(categories.keys()):
    print(f"  {cat}: {categories[cat]} (need {max(0, 201 - categories[cat])} more)")

